package org.example.cpm.diagnostics;
import java.util.*;
public final class DiagnosticBag {private final List<Diagnostic> values;public DiagnosticBag(){this(List.of());}public DiagnosticBag(Collection<Diagnostic> input){var x=new ArrayList<>(input);x.sort(Comparator.comparing(Diagnostic::severity).thenComparing(v->v.location()==null?"":v.location().source().value()).thenComparing(v->v.location()==null||v.location().line()==null?Integer.MAX_VALUE:v.location().line()).thenComparing(v->v.location()==null||v.location().column()==null?Integer.MAX_VALUE:v.location().column()).thenComparing(v->v.location()==null||v.location().jsonPointer()==null?"":v.location().jsonPointer()).thenComparing(v->v.code().value()).thenComparing(v->Objects.toString(v.bone(),"")).thenComparing(v->Objects.toString(v.animation(),"")));values=List.copyOf(x);}public DiagnosticBag add(Diagnostic value){var x=new ArrayList<>(values);x.add(value);return new DiagnosticBag(x);}public DiagnosticBag addAll(DiagnosticBag other){var x=new ArrayList<>(values);x.addAll(other.values);return new DiagnosticBag(x);}public List<Diagnostic> all(){return values;}public boolean hasErrors(){return values.stream().anyMatch(v->v.severity()==Severity.ERROR);}public List<Diagnostic> warnings(){return values.stream().filter(v->v.severity()==Severity.WARNING).toList();}public List<Diagnostic> errors(){return values.stream().filter(v->v.severity()==Severity.ERROR).toList();}}
